import{_ as a,o as e,c as i,a3 as o}from"./chunks/framework.DACwFHq9.js";const g=JSON.parse('{"title":"快捷操作 (Quick Actions) 概览","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/quick-actions/index.md","filePath":"user-guide/tools/llm-chat/quick-actions/index.md","lastUpdated":1778239080000}'),l={name:"user-guide/tools/llm-chat/quick-actions/index.md"};function r(n,t,s,c,d,u){return e(),i("div",null,[...t[0]||(t[0]=[o('<h1 id="快捷操作-quick-actions-概览" tabindex="-1">快捷操作 (Quick Actions) 概览 <a class="header-anchor" href="#快捷操作-quick-actions-概览" aria-label="Permalink to &quot;快捷操作 (Quick Actions) 概览&quot;">​</a></h1><p>快捷操作是一套强大的文本模板与指令系统，允许用户在输入框中通过点击预设按钮，快速对文本进行包装、转换或直接发送复杂指令。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><ul><li><strong>多级关联机制</strong>：快捷操作不是孤立存在的，它们可以关联到不同的维度： <ul><li><strong>全局 (Global)</strong>：在所有会话中均可见。</li><li><strong>智能体 (Agent)</strong>：仅在特定智能体激活时显示。</li><li><strong>用户档案 (User Profile)</strong>：随用户身份切换而变化。</li></ul></li><li><strong>三层覆盖策略</strong>：当多个维度的快捷操作组同时存在时，系统会按优先级聚合显示，确保最相关的操作触手可及。</li></ul><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><ol><li><strong>文本包装</strong>：利用模板语法，一键为选中内容添加 HTML 标签、Markdown 引用或特定的指令前缀。</li><li><strong>指令发送</strong>：配置“自动发送”后，点击按钮即可立即向模型发起请求，无需手动敲击回车。</li><li><strong>多组管理</strong>：支持按功能领域（如代码助手、翻译工具、创意写作）对操作进行分组管理。</li></ol><h2 id="交互位置" tabindex="-1">交互位置 <a class="header-anchor" href="#交互位置" aria-label="Permalink to &quot;交互位置&quot;">​</a></h2><p>在聊天界面的输入框工具栏中，你会看到“闪电”图标。点击即可弹出当前可用的快捷操作列表。</p><hr><p><strong>相关阅读</strong>：</p><ul><li><a href="./template-syntax">模板语法与宏联动</a></li><li><a href="./management">管理与导入导出</a></li></ul>',11)])])}const _=a(l,[["render",r]]);export{g as __pageData,_ as default};
